Scripts.OnLoad:
-- 设置背景为纯黑色，与主窗口保持一致
this:SetBackdropColor(0, 0, 0); -- 纯黑色 RGB(0,0,0)
this:SetBackdropBorderColor(RED_FONT_COLOR.r, RED_FONT_COLOR.g, RED_FONT_COLOR.b, 1);

-- 设置背景为纯黑色，与主窗口保持一致
this:SetBackdropColor(0, 0, 0); -- 纯黑色 RGB(0,0,0)
this:SetBackdropBorderColor(RED_FONT_COLOR.r, RED_FONT_COLOR.g, RED_FONT_COLOR.b, 1);

-- 设置背景为纯黑色，与主窗口保持一致
this:SetBackdropColor(0, 0, 0); -- 纯黑色 RGB(0,0,0)
this:SetBackdropBorderColor(RED_FONT_COLOR.r, RED_FONT_COLOR.g, RED_FONT_COLOR.b, 1);

-- 设置背景为纯黑色，边框保持红色
this:SetBackdropColor(0, 0, 0); -- 纯黑色 RGB(0,0,0) 完全不透明
this:SetBackdropBorderColor(RED_FONT_COLOR.r, RED_FONT_COLOR.g, RED_FONT_COLOR.b, 1);

-- 注册拖动功能
this:RegisterForDrag("LeftButton");

-- 注册VARIABLES_LOADED事件
this:RegisterEvent("VARIABLES_LOADED");

-- 设置背景为纯黑色，与主窗口保持一致
this:SetBackdropColor(0, 0, 0); -- 纯黑色 RGB(0,0,0)
this:SetBackdropBorderColor(RED_FONT_COLOR.r, RED_FONT_COLOR.g, RED_FONT_COLOR.b, 1);

-- 设置背景为纯黑色，与主窗口保持一致
this:SetBackdropColor(0, 0, 0); -- 纯黑色 RGB(0,0,0)
this:SetBackdropBorderColor(0, RED_FONT_COLOR.g, RED_FONT_COLOR.b);

-- 设置背景为纯黑色，与主窗口保持一致
this:SetBackdropColor(0, 0, 0); -- 纯黑色 RGB(0,0,0)
this:SetBackdropBorderColor(RED_FONT_COLOR.r, RED_FONT_COLOR.g, RED_FONT_COLOR.b, 1);
this:RegisterForDrag("LeftButton");

Scripts.OnClick:
if _G["XyTracker_FilterQualityUpdate"] and type(_G["XyTracker_FilterQualityUpdate"]) == "function" then
    _G["XyTracker_FilterQualityUpdate"]();
